import{_ as o,c as l,o as i,ag as a}from"./chunks/framework.DVUBUV_u.js";const h=JSON.parse('{"title":"Релиз 2.1.0","description":"","frontmatter":{"title":"Релиз 2.1.0"},"headers":[],"relativePath":"ru/releases/2.1.0.md","filePath":"ru/releases/2.1.0.md"}'),r={name:"ru/releases/2.1.0.md"};function c(d,e,t,s,n,p){return i(),l("div",null,[...e[0]||(e[0]=[a('<h2 id="_2-1-0-2026-02-02" tabindex="-1">[2.1.0] - 2026-02-02 <a class="header-anchor" href="#_2-1-0-2026-02-02" aria-label="Permalink to &quot;[2.1.0] - 2026-02-02&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>Добавлена новая вкладка управления — <code>Network</code>.</li><li>Проведён редизайн приложения с учётом нового расположения в <code>iframe</code> вместо <code>popup</code>: на экране теперь доступно больше полезной информации.</li><li>Скорректирована вёрстка блоков <code>JSON</code> — блок отображается на всю высоту приложения.</li><li>Исправлено залипание вкладок при раннем открытии приложения: ранее для отображения вкладок <code>Props</code> и <code>Pinia</code> требовалась полная перезагрузка страницы.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена ошибка, при которой избранные элементы <code>Props</code> не находились после обновления страницы или повторного прохождения сценариев.</li><li>Оптимизирована работа с <code>Props</code> для длительных сессий без избыточной нагрузки на CPU, проведён рефакторинг внутренней логики.</li><li>Переработана вкладка <code>Props</code>: улучшена работа с большим количеством объектов и поиск при наведении.</li><li>Из вкладки <code>Props</code> удалён режим <code>Props only</code>.</li></ul><hr><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Добавлен перехват всех вызовов <code>fetch</code> и <code>XMLHttpRequest</code>, за исключением запросов типа <code>OPTIONS</code> и запросов, инициированных расширением.</li><li>Добавлено отображение сводной информации по запросам: статус, метод, имя, время выполнения, размер.</li><li>Добавлен подробный просмотр запроса с разделами: параметры, авторизация, заголовки, запрос, ответ. Отображаются только заголовки, доступные в рамках <code>CORS</code>-ограничений браузера.</li><li>Добавлена возможность приостановки и возобновления записи запросов. Запись включена по умолчанию при первом открытии приложения.</li><li>Добавлен <code>Breakpoint</code> — остановка и модификация исходящего запроса перед отправкой.</li><li>Добавлен <code>Mock Response</code> — перехват заранее выбранного запроса с подменой ответа.</li><li>Добавлено быстрое копирование в буфер обмена URL-адресов, токенов и ключевых элементов.</li><li>Добавлена очистка всех записанных запросов одной кнопкой.</li><li>Реализована событийная архитектура без <code>polling</code> для минимального использования CPU.</li><li>Добавлено автоматическое определение двоичного содержимого — для таких данных отображаются только метаданные.</li></ul>',9)])])}const u=o(r,[["render",c]]);export{h as __pageData,u as default};
